#include <stdio.h>
#include <stdlib.h>

// Structure to represent a trainer
typedef struct {
    int arrivalDay;
    int totalLectures;
    int sadness;
} Trainer;

// Comparison function for sorting trainers based on sadness
int compareTrainers(const void* a, const void* b) {
    Trainer* t1 = (Trainer*)a;
    Trainer* t2 = (Trainer*)b;
    return t2->sadness - t1->sadness;
}

int main() {
    int T;
    scanf("%d", &T);

    while (T--) {
        int N, D;
        scanf("%d %d", &N, &D);

        Trainer* trainers = (Trainer*)malloc(N * sizeof(Trainer));
        for (int i = 0; i < N; i++) {
            scanf("%d %d %d", &trainers[i].arrivalDay, &trainers[i].totalLectures, &trainers[i].sadness);
        }

        // Sort trainers based on sadness
        qsort(trainers, N, sizeof(Trainer), compareTrainers);

        int* availableDays = (int*)malloc(D * sizeof(int));
        for (int i = 0; i < D; i++) {
            availableDays[i] = 1;
        }

        long long totalSadness = 0;
        for (int i = 0; i < N; i++) {
            int assigned = 0;
            for (int j = trainers[i].arrivalDay - 1; j < D; j++) {
                if (availableDays[j] == 1) {
                    availableDays[j] = 0;
                    assigned++;
                    if (assigned == trainers[i].totalLectures) {
                        break;
                    }
                }
            }
            totalSadness += (long long)(trainers[i].totalLectures - assigned) * trainers[i].sadness;
        }

        printf("%lld\n", totalSadness);
        free(trainers);
        free(availableDays);
    }

    return 0;
}

