import java.util.Arrays;
import java.util.Scanner;

public class Main {
    static class Trainer implements Comparable<Trainer> {
        int arrivalDay;
        int totalLectures;
        int sadness;

        public Trainer(int arrivalDay, int totalLectures, int sadness) {
            this.arrivalDay = arrivalDay;
            this.totalLectures = totalLectures;
            this.sadness = sadness;
        }

        @Override
        public int compareTo(Trainer o) {
            return o.sadness - this.sadness;
        }
    }

    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int T = sc.nextInt();

        while (T-- > 0) {
            int N = sc.nextInt();
            int D = sc.nextInt();

            Trainer[] trainers = new Trainer[N];
            for (int i = 0; i < N; i++) {
                trainers[i] = new Trainer(sc.nextInt(), sc.nextInt(), sc.nextInt());
            }

            // Sort trainers based on sadness
            Arrays.sort(trainers);

            int[] availableDays = new int[D];
            long totalSadness = 0;
            for (int i = 0; i < N; i++) {
                int assigned = 0;
                for (int j = trainers[i].arrivalDay - 1; j < D; j++) {
                    if (availableDays[j] == 0) {
                        availableDays[j] = 1;
                        assigned++;
                        if (assigned == trainers[i].totalLectures) {
                            break;
                        }
                    }
                }
                totalSadness += (long) (trainers[i].totalLectures - assigned) * trainers[i].sadness;
            }

            System.out.println(totalSadness);
        }
    }
}

