const fs = require('fs');
const lines = fs.readFileSync(0, 'utf-8').trim().split('\n');
let idx = 0;

// Structure to represent a trainer
class Trainer {
    constructor(arrivalDay, totalLectures, sadness) {
        this.arrivalDay = arrivalDay;
        this.totalLectures = totalLectures;
        this.sadness = sadness;
    }
}

// Comparison function for sorting trainers based on sadness
function compareTrainers(t1, t2) {
    return t2.sadness - t1.sadness;
}

// Main function
function main() {
    const T = parseInt(lines[idx++]);

    for (let i = 0; i < T; i++) {
        const [N, D] = lines[idx++].split(' ').map(Number);

        const trainers = [];
        for (let j = 0; j < N; j++) {
            const [arrivalDay, totalLectures, sadness] = lines[idx++].split(' ').map(Number);
            trainers.push(new Trainer(arrivalDay, totalLectures, sadness));
        }

        // Sort trainers based on sadness
        trainers.sort(compareTrainers);

        const availableDays = new Array(D).fill(0);
        let totalSadness = 0;
        for (const trainer of trainers) {
            let assigned = 0;
            for (let k = trainer.arrivalDay - 1; k < D; k++) {
                if (availableDays[k] === 0) {
                    availableDays[k] = 1;
                    assigned++;
                    if (assigned === trainer.totalLectures) {
                        break;
                    }
                }
            }
            totalSadness += (trainer.totalLectures - assigned) * trainer.sadness;
        }

        console.log(totalSadness);
    }
}

main();
